const e={"MP-1":{title:"Policy and Procedures",body:"[ORG] has developed, documented, and disseminated a Media Protection Policy covering digital and non-digital media containing [SYSTEM] CUI consistent with DoDI 5200.01 and NIST SP 800-88. Reviewed annually. The [ISSO] implements media protection controls.",tools:[]},"MP-2":{title:"Media Access",body:"Access to [SYSTEM] digital and non-digital media is restricted to authorized personnel. [TOOL:gpo] enforces removable media controls on Windows systems. USB storage devices are disabled via [TOOL:gpo] unless specifically authorized by [ISSO]. [TOOL:hbss] controls removable media usage. [TOOL:crowdstrike] monitors for unauthorized removable media. Physical media containing CUI stored in GSA-approved containers. Media access logs reviewed monthly.",tools:["gpo","hbss","crowdstrike"]},"MP-3":{title:"Media Marking",body:"All [SYSTEM] media containing CUI is marked with appropriate CUI designation, handling requirements, and applicable limited dissemination controls per CUI Registry requirements and DoD CUI Program guidance. Electronic files are marked using CUI headers and footers. Physical media labels are applied before use. [ISSO] reviews media marking compliance quarterly.",tools:[]},"MP-4":{title:"Media Storage",body:"[SYSTEM] media containing CUI is stored in controlled areas. Digital media is stored in GSA-approved containers or locked cabinets. Backup media stored at alternate storage site with equivalent protection. Media inventories maintained and reviewed quarterly. CUI media stored separately from unclassified non-CUI materials. Media storage areas included in physical security inspections.",tools:[]},"MP-4(2)":{title:"Media Storage | Automated Restricted Access",body:"[SYSTEM] restricts access to media containing CUI using automated mechanisms. [TOOL:gpo] enforces access controls on removable media storage locations. [TOOL:hbss] device control policies automatically enforce media access restrictions. Physical access to media storage areas is controlled by electronic access control systems using [TOOL:cac]. Media access events are logged to [TOOL:splunk] and reviewed monthly.",tools:["gpo","hbss","cac","splunk"]},"MP-5":{title:"Media Transport",body:"[SYSTEM] media containing CUI is protected during transport outside controlled areas. Digital media is encrypted using FIPS 140-2 approved mechanisms before transport. Transport uses approved courier or secure mailing services with chain of custody documentation. Media transport is tracked using [ORG]'s media log. [ISSO] approves all media transport outside the facility.",tools:[]},"MP-5(4)":{title:"Media Transport | Cryptographic Protection",body:"[SYSTEM] implements cryptographic mechanisms to protect CUI during transport unless protected by an approved alternative physical safeguard. All digital media transported outside controlled areas is encrypted using AES-256 FIPS 140-2 validated encryption. Encryption keys are managed separately from the media. Encrypted transport is verified before media is released for transport. The [ISSO] documents all encrypted media transport events.",tools:[]},"MP-6":{title:"Media Sanitization",body:"[SYSTEM] media is sanitized before disposal, reuse, or removal from organizational control. Sanitization per NIST SP 800-88: overwriting for HDDs, degaussing for magnetic media, physical destruction for SSDs and optical media. [TOOL:hbss] scans media before sanitization to identify stored data. Sanitization is documented with media type, method, date, technician, and verification. Records retained for 3 years. CUI media sanitized to minimum Clear or Purge standard per NIST SP 800-88.",tools:["hbss"]},"MP-6(1)":{title:"Media Sanitization | Review, Approve, Track, Document, Verify",body:"[ORG] reviews, approves, tracks, documents, and verifies media sanitization and disposal actions for [SYSTEM]. The [ISSO] approves all media sanitization requests. Sanitization is performed only by authorized personnel. Each sanitization event is documented in [ORG]'s media sanitization log including: media type, sanitization method, date/time, technician, and verification result. The [ISSM] reviews sanitization logs quarterly.",tools:[]},"MP-6(2)":{title:"Media Sanitization | Equipment Testing",body:"[ORG] tests sanitization equipment and procedures annually to ensure correct performance. Sanitization equipment is calibrated and tested per manufacturer specifications. Test results are documented and reviewed by the [ISSO]. Malfunctioning sanitization equipment is taken out of service until repaired and retested. Alternative sanitization methods are used while equipment is unavailable.",tools:[]},"MP-7":{title:"Media Use",body:"[ORG] restricts removable media use on [SYSTEM]. [TOOL:gpo] disables USB storage ports except where specifically authorized by [ISSO]. [TOOL:hbss] enforces device control policies. [TOOL:crowdstrike] detects and alerts on unauthorized removable media. Authorized removable media must be [ORG]-owned, encrypted, and scanned before use. Personally-owned removable media is prohibited.",tools:["gpo","hbss","crowdstrike"]},"MP-7(1)":{title:"Media Use | Prohibit Use Without Identifiable Owner",body:"[SYSTEM] prohibits the use of removable media in organizational systems when the owner of the media cannot be identified. [TOOL:gpo] restricts removable media to [ORG]-registered devices only. [TOOL:hbss] device control enforces authorized device lists by device ID. Removable media found without identifiable ownership is treated as potentially malicious and reported to the [ISSO]. [TOOL:crowdstrike] alerts when unregistered removable media is connected.",tools:["gpo","hbss","crowdstrike"]},"MP-8":{title:"Media Downgrading",body:"[ORG] establishes and documents a process for downgrading [SYSTEM] media. Media downgrading procedures comply with NSA and DoD guidance for classified media downgrading. Downgrading is performed only by personnel with appropriate authority and training. All downgrading events are documented and approved by the [ISSM]. Media is verified to meet the lower classification level requirements before release.",tools:[]}};export{e as default};
